const agentOutput = $input.first().json;
const originalData = $('Prepare Prompts').first().json.originalData;
const isChangeRequest = $('Prepare Prompts').first().json.isChangeRequest;

// Procesar la respuesta del agente
let response = {
  success: true,
  timestamp: new Date().toISOString()
};

if (isChangeRequest) {
  // Para solicitudes de cambio
  response.type = 'change_request';
  response.message = 'Cambios procesados exitosamente';
  response.request = originalData.request;

  // Incluir detalles de las acciones realizadas
  if (agentOutput.steps) {
    response.actions = agentOutput.steps.map(step => ({
      tool: step.action?.tool,
      input: step.action?.toolInput,
      output: step.observation
    }));
  }

  // Mensaje final del agente
  response.agentSummary = agentOutput.output || agentOutput.text || 'Cambios completados';

} else {
  // Para preguntas conversacionales
  response.type = 'question';
  response.question = originalData.question;
  response.answer = agentOutput.output || agentOutput.text || 'No se pudo generar una respuesta';
  response.conversationId = originalData.conversationId;
}

// Agregar metadatos si existen
if (originalData.metadata) {
  response.metadata = originalData.metadata;
}

return [{
  json: response
}];

// Nodo de manejo de errores
const error = $input.first().error || {};
const context = $input.first().json || {};

const errorResponse = {
  success: false,
  error: {
    message: error.message || 'Error desconocido en el workflow',
    code: error.code || 'UNKNOWN_ERROR',
    stack: error.stack
  },
  context: context,
  timestamp: new Date().toISOString()
};

// Log del error para debugging
console.error('Workflow Error:', errorResponse);

return [{
  json: errorResponse
}];
